#include <bits/stdc++.h>
using namespace std;
char a[255];
int main(){
    int n;
    cin>>a>>n;
    int len=strlen(a);
    while(n--){
        for(int i=0;i<len-1;i++)
            if(a[i]>a[i+1]){
                for(int j=i;j<len-1;j++)
                    a[j]=a[j+1];
                break;
            }
        len--;
    }
    int m=0;
    while(m<len && a[m]=='0')m++;
    if(m==len)cout<<0;
    else{
        for(m=m;m<len;m++)cout<<a[m];
    }
    return 0;
}
